mapper.select:
SELECT
    st.id as id,
    st.customer_id as customerId,
    st.subject as subject,
    st.category as category,
    st.priority as priority,
    st.state_id as stateId,
    st.assigned_agent_id as assignedAgentId,
    st.reopen_count as reopenCount,
    st.created_at as createdAt
FROM support_tickets st

    AND st.id = #{id}
    AND st.customer_id = #{customerId}
    AND st.subject LIKE CONCAT('%', #{subject}, '%')
    AND st.category = #{category}
    AND st.priority = #{priority}
    AND st.state_id = #{stateId}
    AND st.assigned_agent_id = #{assignedAgentId}
    AND st.created_at >= #{startDate}
    AND st.created_at <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM support_tickets st

    AND st.id = #{id}
    AND st.customer_id = #{customerId}
    AND st.subject LIKE CONCAT('%', #{subject}, '%')
    AND st.category = #{category}
    AND st.priority = #{priority}
    AND st.state_id = #{stateId}
    AND st.assigned_agent_id = #{assignedAgentId}
    AND st.created_at >= #{startDate}
    AND st.created_at <= #{endDate}

SELECT COUNT(*)
FROM support_tickets st
WHERE st.assigned_agent_id = #{assignedAgentId}

SELECT COUNT(*)
FROM support_tickets st
WHERE st.priority = #{priority}

SELECT COUNT(*)
FROM support_tickets st
WHERE st.customer_id = #{customerId}
